classdef GpuHeightSweep
    %GPUHEIGHTSWEEP Host-coordinated gpuArray plane-sweep boundary.
    %
    % G1 keeps camera projection and Jacobians in CPU double precision. One
    % host coordinator owns one device; thread workers do not submit device
    % work. PREFLIGHT is deterministic without hardware when the caller
    % supplies AvailableMemoryBytes and InspectDevice=false.
    %
    % Traceability: docs/implementation_plan.md G1.0--G1.3; D040;
    % algo/main.tex Algorithm 1, lines 4--9 and Sec. 12.

    methods (Static)
        function report = preflight(imageSize, labelCount, options)
            %PREFLIGHT Estimate the declared G1 device payload.
            %
            % The estimate includes full resident inputs, one exact-halo tile,
            % one label block, an optional tile cost volume, compact reduction
            % state, optional full-volume SGM, and a declared scratch
            % multiplier. It excludes host CPU geometry arrays and final
            % CPU-double geometry products.

            arguments
                imageSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive}
                labelCount (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive}
                options.Channel (1, 1) string ...
                    {mustBeMember(options.Channel, ...
                    ["Zncc", "Spin2T3"])} = "Zncc"
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = ...
                    [256, 256]
                options.IntegrationRadius (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 3
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.RetainTileCostVolume (1, 1) logical = true
                options.RetainFullCostVolume (1, 1) logical = false
                options.RunSgm (1, 1) logical = false
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.ScratchFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual(options.ScratchFraction, 0), ...
                    mustBeLessThanOrEqual(options.ScratchFraction, 1)} = 0.35
                options.ReserveFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual(options.ReserveFraction, 0), ...
                    mustBeLessThan(options.ReserveFraction, 1)} = 0.2
                options.AvailableMemoryBytes (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0
                options.DeviceIndex (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.InspectDevice (1, 1) logical = true
            end

            if options.WorkingPrecision == "single"
                b = 4;
            else
                b = 8;
            end
            np = prod(imageSize);
            ts = min(options.TileSize, imageSize);
            es = ts + 2 .* options.IntegrationRadius;
            nt = prod(ts);
            ne = prod(es);
            nb = min(options.LabelBlockSize, labelCount);

            if options.Channel == "Zncc"
                resident = np .* (2 .* b + 2);
                referenceTile = ne .* (b + 1);
                sampleBlock = ne .* nb .* (12 .* b + 2);
                geometryBlock = 0;
                filterBlock = nt .* nb .* 10 .* b;
                residentDefinition = ...
                    "reference/moving intensity plus two logical masks";
            else
                resident = np .* (4 .* b + 2);
                referenceTile = ne .* (2 .* b + 1);
                sampleBlock = ne .* nb .* (24 .* b + 2);
                geometryBlock = ne .* nb .* 4 .* b;
                filterBlock = nt .* nb .* 12 .* b;
                residentDefinition = ...
                    "reference/moving Gx/Gy plus two logical gradient masks";
            end
            if options.RetainTileCostVolume
                costVolume = nt .* labelCount .* b;
            else
                costVolume = 0;
            end
            reduction = nt .* (6 .* b + 10);
            if options.RetainFullCostVolume || options.RunSgm
                fullCostVolume = np .* labelCount .* b;
            else
                fullCostVolume = 0;
            end
            if options.RunSgm
                % HeightSgm.aggregateVectorized keeps the exact input and
                % aggregate volumes resident. The additional two numeric
                % volumes conservatively cover selection/assignment
                % temporaries; invalid candidates remain a logical volume.
                sgmAggregate = np .* labelCount .* b;
                sgmTransient = 2 .* np .* labelCount .* b;
                sgmValidCandidate = np .* labelCount;
                sgmScanline = 4 .* max(imageSize) .* labelCount .* b;
                sgmCompact = np .* (10 .* b + 10);
            else
                sgmAggregate = 0;
                sgmTransient = 0;
                sgmValidCandidate = 0;
                sgmScanline = 0;
                sgmCompact = 0;
            end
            working = referenceTile + sampleBlock + geometryBlock ...
                + filterBlock + costVolume + reduction;
            retained = fullCostVolume + sgmAggregate ...
                + sgmValidCandidate + sgmCompact;
            transient = sgmTransient + sgmScanline;
            scratch = ceil(options.ScratchFraction .* ...
                (working + retained + transient));
            required = resident + working + retained + transient + scratch;

            availableDeviceCount = gpuDeviceCount("available");
            deviceAvailable = availableDeviceCount > 0;
            deviceName = "not inspected";
            actualAvailable = 0;
            selectedDevice = options.DeviceIndex;
            if options.InspectDevice && deviceAvailable
                if selectedDevice == 0
                    selectedDevice = 1;
                end
                if selectedDevice > availableDeviceCount
                    error("GpuHeightSweep:DeviceIndexUnavailable", ...
                        "DeviceIndex %d exceeds %d available GPU devices.", ...
                        selectedDevice, availableDeviceCount);
                end
                device = gpuDevice(selectedDevice);
                deviceName = string(device.Name);
                actualAvailable = double(device.AvailableMemory);
            elseif ~deviceAvailable
                deviceName = "no supported GPU";
            end

            if options.AvailableMemoryBytes > 0
                available = options.AvailableMemoryBytes;
                budgetSource = "caller override";
            else
                available = actualAvailable;
                if actualAvailable > 0
                    budgetSource = "gpuDevice.AvailableMemory";
                else
                    budgetSource = "unavailable";
                end
            end
            budget = floor((1 - options.ReserveFraction) .* available);
            fitKnown = available > 0;
            fits = fitKnown && required <= budget;
            if ~deviceAvailable && options.AvailableMemoryBytes == 0
                status = "device-unavailable";
            elseif ~fitKnown
                status = "memory-budget-unknown";
            elseif fits
                status = "fits";
            else
                status = "exceeds-budget";
            end

            report = struct( ...
                "Status", status, ...
                "Channel", options.Channel, ...
                "WorkingPrecision", options.WorkingPrecision, ...
                "ImageSize", imageSize, ...
                "LabelCount", labelCount, ...
                "TileSize", ts, ...
                "ExactHaloTileSize", es, ...
                "IntegrationRadiusPixels", options.IntegrationRadius, ...
                "LabelBlockSize", nb, ...
                "RetainTileCostVolume", options.RetainTileCostVolume, ...
                "RetainFullCostVolume", ...
                options.RetainFullCostVolume || options.RunSgm, ...
                "RunSgm", options.RunSgm, ...
                "SgmDirectionCount", options.DirectionCount, ...
                "AvailableDeviceCount", availableDeviceCount, ...
                "DeviceAvailable", deviceAvailable, ...
                "DeviceIndex", selectedDevice, ...
                "DeviceName", deviceName, ...
                "AvailableMemoryBytes", available, ...
                "MemoryBudgetBytes", budget, ...
                "MemoryBudgetSource", budgetSource, ...
                "ReserveFraction", options.ReserveFraction, ...
                "ScratchFraction", options.ScratchFraction, ...
                "ResidentInputBytes", resident, ...
                "ReferenceTileBytes", referenceTile, ...
                "LabelBlockSamplingBytes", sampleBlock, ...
                "LabelBlockGeometryBytes", geometryBlock, ...
                "LabelBlockFilterBytes", filterBlock, ...
                "TileCostVolumeBytes", costVolume, ...
                "TileReductionBytes", reduction, ...
                "FullCostVolumeBytes", fullCostVolume, ...
                "SgmAggregateBytes", sgmAggregate, ...
                "SgmTransientBytes", sgmTransient, ...
                "SgmValidCandidateBytes", sgmValidCandidate, ...
                "SgmMaximumScanlineStateBytes", sgmScanline, ...
                "SgmCompactSelectionBytes", sgmCompact, ...
                "ScratchBytes", scratch, ...
                "RequiredDeviceBytes", required, ...
                "RequiredDeviceGiB", required ./ 2 ^ 30, ...
                "MemoryFitKnown", fitKnown, ...
                "FitsAvailableMemory", fits, ...
                "ResidentInputDefinition", residentDefinition, ...
                "Execution", ...
                "one host coordinator; one GPU; no thread workers", ...
                "Geometry", ...
                "CPU double w(p,z), dw/dp, height labels, and outputs", ...
                "ArrayLayout", "[row,column,label]", ...
                "InvalidPolicy", ...
                "logical masks and NaN costs remain explicit", ...
                "Definition", ...
                "conservative MATLAB payload model; validate against " ...
                + "observed Windows device usage before promotion");
        end

        function result = runZncc(sweep, z, options)
            %RUNZNCC Host-coordinated exact-geometry ZNCC plane sweep.
            %
            % CPU-array execution exercises the identical coordinator and
            % kernels without claiming acceleration. GPU execution keeps full
            % intensity/mask inputs resident, evaluates camera warps on the
            % host in double, builds one tile cost volume on-device, reduces
            % it there, and gathers compact tile products. A full host cost
            % volume is optional and intended only for equivalence controls.
            %
            % Traceability: algo/main.tex Algorithm 1, lines 4--9;
            % Eqs. (68)--(69); docs/implementation_plan.md G1.1.

            arguments
                sweep (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeGpuLabels}
                options.ExecutionTarget (1, 1) string ...
                    {mustBeMember(options.ExecutionTarget, ...
                    ["gpu", "cpu-array"])} = "gpu"
                options.DeviceIndex (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = ...
                    [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.StoreCostVolume (1, 1) logical = false
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.ReserveFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual(options.ReserveFraction, 0), ...
                    mustBeLessThan(options.ReserveFraction, 1)} = 0.2
            end

            curve = sweep.CostCurve;
            imageSize = curve.Geometry.ReferenceCamera.ImageSize;
            radius = curve.Reference.IntegrationRadius;
            target = options.ExecutionTarget;
            if target == "gpu"
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Zncc", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=options.DeviceIndex, InspectDevice=true);
                if ~plan.DeviceAvailable
                    error("GpuHeightSweep:DeviceUnavailable", ...
                        "No supported MATLAB GPU device is available.");
                end
                if ~plan.FitsAvailableMemory
                    error("GpuHeightSweep:DeviceMemoryExceeded", ...
                        ["The declared G1 ZNCC payload requires %.3f GiB " ...
                        "but only %.3f GiB is budgeted after reserve."], ...
                        plan.RequiredDeviceGiB, ...
                        plan.MemoryBudgetBytes ./ 2 ^ 30);
                end
                device = gpuDevice(plan.DeviceIndex);
            else
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Zncc", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=0, InspectDevice=false);
                device = [];
            end

            totalTimer = tic;
            transferTimer = tic;
            ref = cast(curve.Reference.Image, options.WorkingPrecision);
            mov = cast(curve.Moving.Image, options.WorkingPrecision);
            refValid = curve.Reference.InputValid;
            movValid = curve.Moving.InputValid;
            if target == "gpu"
                ref = gpuArray(ref);
                mov = gpuArray(mov);
                refValid = gpuArray(refValid);
                movValid = gpuArray(movValid);
                wait(device);
            end
            sourceTransferSeconds = toc(transferTimer);

            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            labelIndex = zeros(imageSize);
            best = nan(imageSize, options.WorkingPrecision);
            second = nan(imageSize, options.WorkingPrecision);
            previous = nan(imageSize, options.WorkingPrecision);
            next = nan(imageSize, options.WorkingPrecision);
            margin = nan(imageSize, options.WorkingPrecision);
            curvature = nan(imageSize, options.WorkingPrecision);
            validLabelCount = zeros(imageSize);
            rawValid = false(imageSize);
            if options.StoreCostVolume
                costVolume = nan( ...
                    [imageSize, nl], options.WorkingPrecision);
            else
                costVolume = zeros( ...
                    [imageSize, 0], options.WorkingPrecision);
            end

            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            geometrySeconds = 0;
            arraySeconds = 0;
            reductionSeconds = 0;
            outputTransferSeconds = 0;
            tileCount = 0;
            maximumTileCostBytes = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileCount = tileCount + 1;
                    bounds = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                    q = GpuHeightSweep.evaluateZnccTile( ...
                        curve, ref, refValid, mov, movValid, bounds, z, ...
                        target, device, options);
                    rows = bounds(1):bounds(2);
                    columns = bounds(3):bounds(4);
                    labelIndex(rows, columns) = q.LabelIndex;
                    best(rows, columns) = q.BestCost;
                    second(rows, columns) = q.SecondBestCost;
                    previous(rows, columns) = q.PreviousLabelCost;
                    next(rows, columns) = q.NextLabelCost;
                    margin(rows, columns) = q.CostMargin;
                    curvature(rows, columns) = ...
                        q.LocalCurvaturePerMetreSquared;
                    validLabelCount(rows, columns) = q.ValidLabelCount;
                    rawValid(rows, columns) = q.Valid;
                    if options.StoreCostVolume
                        costVolume(rows, columns, :) = q.CostVolume;
                    end
                    geometrySeconds = geometrySeconds + q.GeometrySeconds;
                    arraySeconds = arraySeconds + q.ArraySeconds;
                    reductionSeconds = ...
                        reductionSeconds + q.ReductionSeconds;
                    outputTransferSeconds = ...
                        outputTransferSeconds + q.OutputTransferSeconds;
                    maximumTileCostBytes = max( ...
                        maximumTileCostBytes, q.TileCostBytes);
                end
            end

            height = nan(imageSize);
            selected = find(rawValid);
            height(selected) = z(labelIndex(selected));
            projection = sweep.projectHeightMap( ...
                height, rawValid, DeltaHeight=options.DeltaHeight, ...
                Products=["Correspondence", "Observability"]);
            outputInfo = whos("height", "labelIndex", "best", ...
                "second", "previous", "next", "margin", ...
                "curvature", "validLabelCount", "costVolume");
            totalSeconds = toc(totalTimer);

            result = struct( ...
                "Channel", "Zncc", ...
                "ComputedChannels", "Zncc", ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", projection.HeightMetres, ...
                "CorrespondenceXY", projection.CorrespondenceXY, ...
                "ObservabilityPixelsPerMetre", ...
                projection.ObservabilityPixelsPerMetre, ...
                "Valid", projection.Valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", validLabelCount ./ nl, ...
                "CostVolume", costVolume, ...
                "CostVolumeByChannel", ...
                GpuHeightSweep.optionalCostStruct( ...
                costVolume, options.StoreCostVolume), ...
                "StoreCostVolumes", options.StoreCostVolume, ...
                "SelectedHeightByChannel", ...
                struct("Zncc", height), ...
                "ExecutionTarget", target, ...
                "Preflight", plan, ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", curve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                curve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", ...
                "vectorized bilinear; all nonzero-weight samples required", ...
                "Regularization", "none", ...
                "TileBoundaryPolicy", ...
                "core centers partitioned; exact integration halo", ...
                "SpatialHaloPixels", radius, ...
                "Runtime", struct( ...
                "TotalSeconds", totalSeconds, ...
                "SourceTransferSeconds", sourceTransferSeconds, ...
                "CpuGeometrySeconds", geometrySeconds, ...
                "ArrayKernelSeconds", arraySeconds, ...
                "ArrayReductionSeconds", reductionSeconds, ...
                "OutputTransferSeconds", outputTransferSeconds, ...
                "PixelCount", prod(imageSize), ...
                "LabelCount", nl, ...
                "PixelLabelCount", prod(imageSize) .* nl, ...
                "PixelLabelsPerSecond", ...
                prod(imageSize) .* nl ./ totalSeconds, ...
                "TileCount", tileCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "MaximumTileCostBytes", maximumTileCostBytes, ...
                "OutputArrayBytes", sum([outputInfo.bytes]), ...
                "Execution", ...
                "single host coordinator; serial tiles; array kernels", ...
                "NumThreadWorkers", 0, ...
                "Precision", options.WorkingPrecision, ...
                "GeometryPrecision", "double"));
        end

        function result = runZnccSgm(sweep, z, options)
            %RUNZNCCSGM Device-resident ZNCC and physical-height SGM.
            %
            % Exact plane warps remain CPU double. Tile ZNCC costs assemble
            % into one scene-wide array on the selected target, and the
            % unchanged vectorized SGM recurrence runs there without a host
            % cost-volume transfer. Only compact selections are gathered by
            % default; optional host volumes are equivalence diagnostics.
            %
            % Traceability: algo/main.tex Algorithm 1, lines 4--18 and
            % Eqs. (68)--(75); docs/implementation_plan.md G1.3.

            arguments
                sweep (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeGpuLabels}
                options.ExecutionTarget (1, 1) string ...
                    {mustBeMember(options.ExecutionTarget, ...
                    ["gpu", "cpu-array"])} = "gpu"
                options.DeviceIndex (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = ...
                    [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 8
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.StoreCostVolumes (1, 1) logical = false
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.PenaltyPerMetre (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.02
                options.MaximumPenalty (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 0.2
                options.DirectionCount (1, 1) double ...
                    {mustBeMember(options.DirectionCount, [4, 8])} = 8
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.ReserveFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual(options.ReserveFraction, 0), ...
                    mustBeLessThan(options.ReserveFraction, 1)} = 0.2
            end

            curve = sweep.CostCurve;
            imageSize = curve.Geometry.ReferenceCamera.ImageSize;
            radius = curve.Reference.IntegrationRadius;
            target = options.ExecutionTarget;
            if target == "gpu"
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Zncc", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    RetainFullCostVolume=true, RunSgm=true, ...
                    DirectionCount=options.DirectionCount, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=options.DeviceIndex, InspectDevice=true);
                if ~plan.DeviceAvailable
                    error("GpuHeightSweep:DeviceUnavailable", ...
                        "No supported MATLAB GPU device is available.");
                end
                if ~plan.FitsAvailableMemory
                    error("GpuHeightSweep:SgmDeviceMemoryExceeded", ...
                        ["Full-volume device SGM requires %.3f GiB but " ...
                        "only %.3f GiB is budgeted after reserve. Use " ...
                        "a smaller ROI/label set or the later streamed " ...
                        "G2 SGM path."], plan.RequiredDeviceGiB, ...
                        plan.MemoryBudgetBytes ./ 2 ^ 30);
                end
                device = gpuDevice(plan.DeviceIndex);
            else
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Zncc", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    RetainFullCostVolume=true, RunSgm=true, ...
                    DirectionCount=options.DirectionCount, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=0, InspectDevice=false);
                device = [];
            end

            totalTimer = tic;
            memoryStage = ["before-source"; "after-source"; ...
                "after-cost-volume"; "after-sgm"; ...
                "after-output-gather"];
            availableDeviceBytes = nan(numel(memoryStage), 1);
            if target == "gpu"
                availableDeviceBytes(1) = double(device.AvailableMemory);
            end
            transferTimer = tic;
            ref = cast(curve.Reference.Image, options.WorkingPrecision);
            mov = cast(curve.Moving.Image, options.WorkingPrecision);
            refValid = curve.Reference.InputValid;
            movValid = curve.Moving.InputValid;
            if target == "gpu"
                ref = gpuArray(ref);
                mov = gpuArray(mov);
                refValid = gpuArray(refValid);
                movValid = gpuArray(movValid);
                wait(device);
            end
            sourceTransferSeconds = toc(transferTimer);
            if target == "gpu"
                sourceTransferBytes = plan.ResidentInputBytes;
                availableDeviceBytes(2) = double(device.AvailableMemory);
            else
                sourceTransferBytes = 0;
            end

            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            cost = nan([imageSize, nl], "like", ref);
            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            geometrySeconds = 0;
            arraySeconds = 0;
            tileCount = 0;
            maximumTileCostBytes = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileCount = tileCount + 1;
                    bounds = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                    [c, gt, at] = GpuHeightSweep.computeZnccTileCost( ...
                        curve, ref, refValid, mov, movValid, bounds, z, ...
                        target, device, options);
                    rows = bounds(1):bounds(2);
                    columns = bounds(3):bounds(4);
                    cost(rows, columns, :) = c;
                    geometrySeconds = geometrySeconds + gt;
                    arraySeconds = arraySeconds + at;
                    maximumTileCostBytes = max( ...
                        maximumTileCostBytes, ...
                        GpuHeightSweep.arrayBytes(c));
                end
            end
            GpuHeightSweep.synchronize(target, device);
            if target == "gpu"
                availableDeviceBytes(3) = double(device.AvailableMemory);
            end

            sgmTimer = tic;
            s = HeightSgm.aggregateVectorized(cost, z, ...
                PenaltyPerMetre=options.PenaltyPerMetre, ...
                MaximumPenalty=options.MaximumPenalty, ...
                DirectionCount=options.DirectionCount, ...
                StorePathCosts=false, ReturnDirectionCount=false);
            GpuHeightSweep.synchronize(target, device);
            sgmSeconds = toc(sgmTimer);
            if target == "gpu"
                availableDeviceBytes(4) = double(device.AvailableMemory);
            end

            outputTransferTimer = tic;
            labelIndex = GpuHeightSweep.toHost(s.LabelIndex);
            validSelection = GpuHeightSweep.toHost(s.Valid);
            best = GpuHeightSweep.toHost(s.BestCost);
            second = GpuHeightSweep.toHost(s.SecondBestCost);
            margin = GpuHeightSweep.toHost(s.CostMargin);
            rawLabelIndex = GpuHeightSweep.toHost(s.RawLabelIndex);
            rawBest = GpuHeightSweep.toHost(s.RawBestCost);
            rawSecond = GpuHeightSweep.toHost(s.RawSecondBestCost);
            rawMargin = GpuHeightSweep.toHost(s.RawCostMargin);
            if options.StoreCostVolumes
                costVolume = GpuHeightSweep.toHost(s.RawCost);
                aggregatedCost = ...
                    GpuHeightSweep.toHost(s.AggregatedCost);
            else
                costVolume = zeros( ...
                    [imageSize, 0], options.WorkingPrecision);
                aggregatedCost = zeros( ...
                    [imageSize, 0], options.WorkingPrecision);
            end
            outputTransferSeconds = toc(outputTransferTimer);
            if target == "gpu"
                availableDeviceBytes(5) = double(device.AvailableMemory);
                outputTransferBytes = ...
                    GpuHeightSweep.arrayBytes(labelIndex) ...
                    + GpuHeightSweep.arrayBytes(validSelection) ...
                    + GpuHeightSweep.arrayBytes(best) ...
                    + GpuHeightSweep.arrayBytes(second) ...
                    + GpuHeightSweep.arrayBytes(margin) ...
                    + GpuHeightSweep.arrayBytes(rawLabelIndex) ...
                    + GpuHeightSweep.arrayBytes(rawBest) ...
                    + GpuHeightSweep.arrayBytes(rawSecond) ...
                    + GpuHeightSweep.arrayBytes(rawMargin) ...
                    + GpuHeightSweep.arrayBytes(costVolume) ...
                    + GpuHeightSweep.arrayBytes(aggregatedCost);
            else
                outputTransferBytes = 0;
            end
            if target == "gpu"
                sampledUsedBytes = max( ...
                    availableDeviceBytes(1) - availableDeviceBytes, 0);
                sampledPeakBytes = max(sampledUsedBytes);
                preflightCoversSample = ...
                    plan.RequiredDeviceBytes >= sampledPeakBytes;
            else
                sampledUsedBytes = nan(size(availableDeviceBytes));
                sampledPeakBytes = NaN;
                preflightCoversSample = false;
            end
            deviceMemorySamples = table(memoryStage, ...
                availableDeviceBytes, sampledUsedBytes, ...
                VariableNames=["Stage", "AvailableBytes", ...
                "UsedFromBaselineBytes"]);

            height = nan(imageSize);
            selected = validSelection & labelIndex > 0;
            height(selected) = z(labelIndex(selected));
            rawHeight = nan(imageSize);
            rawSelected = rawLabelIndex > 0;
            rawHeight(rawSelected) = z(rawLabelIndex(rawSelected));
            projectionTimer = tic;
            projection = sweep.projectHeightMap( ...
                height, validSelection, DeltaHeight=options.DeltaHeight, ...
                Products=["Correspondence", "Observability"]);
            projectionSeconds = toc(projectionTimer);
            totalSeconds = toc(totalTimer);
            outputInfo = whos("height", "rawHeight", "labelIndex", ...
                "validSelection", "best", "second", "margin", ...
                "rawLabelIndex", "rawBest", "rawSecond", ...
                "rawMargin", "costVolume", "aggregatedCost");

            result = struct( ...
                "Channel", "Zncc", ...
                "ComputedChannels", "Zncc", ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", projection.HeightMetres, ...
                "CorrespondenceXY", projection.CorrespondenceXY, ...
                "ObservabilityPixelsPerMetre", ...
                projection.ObservabilityPixelsPerMetre, ...
                "Valid", projection.Valid, ...
                "SgmSelectionValid", validSelection, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "RawHeightMetres", rawHeight, ...
                "RawLabelIndex", rawLabelIndex, ...
                "RawBestCost", rawBest, ...
                "RawSecondBestCost", rawSecond, ...
                "RawCostMargin", rawMargin, ...
                "CostVolume", costVolume, ...
                "AggregatedCost", aggregatedCost, ...
                "StoreCostVolumes", options.StoreCostVolumes, ...
                "ExecutionTarget", target, ...
                "Preflight", plan, ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", curve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                curve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Interpolation", ...
                "vectorized bilinear; all nonzero-weight samples required", ...
                "Regularization", "physical-height SGM", ...
                "Sgm", struct( ...
                "PenaltyPerMetre", options.PenaltyPerMetre, ...
                "MaximumPenalty", options.MaximumPenalty, ...
                "DirectionCount", options.DirectionCount, ...
                "PenaltyModel", ...
                "min(PenaltyPerMetre*abs(deltaZ),MaximumPenalty)", ...
                "Execution", "vectorized scanline on selected target", ...
                "DirectionRuntimeSeconds", s.DirectionRuntimeSeconds, ...
                "MaximumScanlineStateBytes", ...
                s.MaximumScanlineStateBytes), ...
                "TileBoundaryPolicy", ...
                "cost cores partitioned; SGM spans the complete image", ...
                "SpatialHaloPixels", radius, ...
                "Runtime", struct( ...
                "TotalSeconds", totalSeconds, ...
                "SourceTransferSeconds", sourceTransferSeconds, ...
                "SourceTransferBytes", sourceTransferBytes, ...
                "CpuGeometrySeconds", geometrySeconds, ...
                "ZnccArrayKernelSeconds", arraySeconds, ...
                "SgmArraySeconds", sgmSeconds, ...
                "OutputTransferSeconds", outputTransferSeconds, ...
                "OutputTransferBytes", outputTransferBytes, ...
                "FinalCpuProjectionSeconds", projectionSeconds, ...
                "EstimatedDevicePeakBytes", plan.RequiredDeviceBytes, ...
                "EstimatedDevicePeakGiB", plan.RequiredDeviceGiB, ...
                "DeviceMemorySamples", deviceMemorySamples, ...
                "SampledPeakDeviceBytes", sampledPeakBytes, ...
                "PreflightCoversSampledPeak", ...
                preflightCoversSample, ...
                "SampledPeakDefinition", ...
                "named-stage lower bound; transient kernel peak excluded", ...
                "PixelCount", prod(imageSize), ...
                "LabelCount", nl, ...
                "PixelLabelCount", prod(imageSize) .* nl, ...
                "PixelLabelsPerSecond", ...
                prod(imageSize) .* nl ./ totalSeconds, ...
                "TileCount", tileCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "MaximumTileCostBytes", maximumTileCostBytes, ...
                "OutputArrayBytes", sum([outputInfo.bytes]), ...
                "Execution", ...
                "one host coordinator; device cost and SGM; host projection", ...
                "NumThreadWorkers", 0, ...
                "Precision", options.WorkingPrecision, ...
                "GeometryPrecision", "double"));
        end

        function result = runT3(sweep, z, options)
            %RUNT3 Host-coordinated exact-transport spin-2 plane sweep.
            %
            % Exact w(p,z) and A=dw/dp are evaluated in CPU double. Native
            % gradients, A^T transport, descriptor integration, cost, and tile
            % reductions execute on the selected array target. T3 remains a
            % diagnostic channel after the P2 RD1 rejection.
            %
            % Traceability: algo/main.tex Eqs. (22), (25), and (58),
            % Algorithm 1 lines 4--9; implementation plan G1.2.

            arguments
                sweep (1, 1) DenseHeightSweep
                z (1, :) double ...
                    {mustBeFinite, mustBeGpuLabels}
                options.ExecutionTarget (1, 1) string ...
                    {mustBeMember(options.ExecutionTarget, ...
                    ["gpu", "cpu-array"])} = "gpu"
                options.DeviceIndex (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
                options.TileSize (1, 2) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = ...
                    [256, 256]
                options.LabelBlockSize (1, 1) double ...
                    {mustBeFinite, mustBeInteger, mustBePositive} = 4
                options.WorkingPrecision (1, 1) string ...
                    {mustBeMember(options.WorkingPrecision, ...
                    ["single", "double"])} = "single"
                options.StoreCostVolume (1, 1) logical = false
                options.MinimumSupportFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual( ...
                    options.MinimumSupportFraction, 0), ...
                    mustBeLessThanOrEqual( ...
                    options.MinimumSupportFraction, 1)} = 0.8
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.RequireOrientationPreserving (1, 1) logical = true
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.ReserveFraction (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeGreaterThanOrEqual(options.ReserveFraction, 0), ...
                    mustBeLessThan(options.ReserveFraction, 1)} = 0.2
            end

            curve = sweep.CostCurve;
            if ~curve.Reference.GradientsPrepared ...
                    || ~curve.Moving.GradientsPrepared
                error("GpuHeightSweep:GradientsNotPrepared", ...
                    "G1.2 T3 execution requires prepared native gradients.");
            end
            imageSize = curve.Geometry.ReferenceCamera.ImageSize;
            radius = curve.Reference.IntegrationRadius;
            target = options.ExecutionTarget;
            if target == "gpu"
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Spin2T3", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=options.DeviceIndex, InspectDevice=true);
                if ~plan.DeviceAvailable
                    error("GpuHeightSweep:DeviceUnavailable", ...
                        "No supported MATLAB GPU device is available.");
                end
                if ~plan.FitsAvailableMemory
                    error("GpuHeightSweep:DeviceMemoryExceeded", ...
                        ["The declared G1 T3 payload requires %.3f GiB " ...
                        "but only %.3f GiB is budgeted after reserve."], ...
                        plan.RequiredDeviceGiB, ...
                        plan.MemoryBudgetBytes ./ 2 ^ 30);
                end
                device = gpuDevice(plan.DeviceIndex);
            else
                plan = GpuHeightSweep.preflight( ...
                    imageSize, numel(z), Channel="Spin2T3", ...
                    WorkingPrecision=options.WorkingPrecision, ...
                    TileSize=options.TileSize, ...
                    IntegrationRadius=radius, ...
                    LabelBlockSize=options.LabelBlockSize, ...
                    RetainTileCostVolume=true, ...
                    ReserveFraction=options.ReserveFraction, ...
                    DeviceIndex=0, InspectDevice=false);
                device = [];
            end

            totalTimer = tic;
            transferTimer = tic;
            rgx = cast(curve.Reference.Gx, options.WorkingPrecision);
            rgy = cast(curve.Reference.Gy, options.WorkingPrecision);
            mgx = cast(curve.Moving.Gx, options.WorkingPrecision);
            mgy = cast(curve.Moving.Gy, options.WorkingPrecision);
            refValid = curve.Reference.GradientValid;
            movValid = curve.Moving.GradientValid;
            if target == "gpu"
                rgx = gpuArray(rgx);
                rgy = gpuArray(rgy);
                mgx = gpuArray(mgx);
                mgy = gpuArray(mgy);
                refValid = gpuArray(refValid);
                movValid = gpuArray(movValid);
                wait(device);
            end
            sourceTransferSeconds = toc(transferTimer);

            nr = imageSize(1);
            nc = imageSize(2);
            nl = numel(z);
            labelIndex = zeros(imageSize);
            best = nan(imageSize, options.WorkingPrecision);
            second = nan(imageSize, options.WorkingPrecision);
            previous = nan(imageSize, options.WorkingPrecision);
            next = nan(imageSize, options.WorkingPrecision);
            margin = nan(imageSize, options.WorkingPrecision);
            curvature = nan(imageSize, options.WorkingPrecision);
            validLabelCount = zeros(imageSize);
            confidence = nan(imageSize, options.WorkingPrecision);
            support = nan(imageSize, options.WorkingPrecision);
            rawValid = false(imageSize);
            if options.StoreCostVolume
                costVolume = nan( ...
                    [imageSize, nl], options.WorkingPrecision);
            else
                costVolume = zeros( ...
                    [imageSize, 0], options.WorkingPrecision);
            end

            rowStarts = 1:options.TileSize(1):nr;
            columnStarts = 1:options.TileSize(2):nc;
            geometrySeconds = 0;
            arraySeconds = 0;
            reductionSeconds = 0;
            outputTransferSeconds = 0;
            tileCount = 0;
            maximumTileCostBytes = 0;
            for rowStart = rowStarts
                for columnStart = columnStarts
                    tileCount = tileCount + 1;
                    bounds = [rowStart, ...
                        min(rowStart + options.TileSize(1) - 1, nr), ...
                        columnStart, ...
                        min(columnStart + options.TileSize(2) - 1, nc)];
                    q = GpuHeightSweep.evaluateT3Tile( ...
                        curve, rgx, rgy, refValid, mgx, mgy, movValid, ...
                        bounds, z, target, device, options);
                    rows = bounds(1):bounds(2);
                    columns = bounds(3):bounds(4);
                    labelIndex(rows, columns) = q.LabelIndex;
                    best(rows, columns) = q.BestCost;
                    second(rows, columns) = q.SecondBestCost;
                    previous(rows, columns) = q.PreviousLabelCost;
                    next(rows, columns) = q.NextLabelCost;
                    margin(rows, columns) = q.CostMargin;
                    curvature(rows, columns) = ...
                        q.LocalCurvaturePerMetreSquared;
                    validLabelCount(rows, columns) = q.ValidLabelCount;
                    confidence(rows, columns) = q.BestConfidence;
                    support(rows, columns) = q.BestSupport;
                    rawValid(rows, columns) = q.Valid;
                    if options.StoreCostVolume
                        costVolume(rows, columns, :) = q.CostVolume;
                    end
                    geometrySeconds = geometrySeconds + q.GeometrySeconds;
                    arraySeconds = arraySeconds + q.ArraySeconds;
                    reductionSeconds = ...
                        reductionSeconds + q.ReductionSeconds;
                    outputTransferSeconds = ...
                        outputTransferSeconds + q.OutputTransferSeconds;
                    maximumTileCostBytes = max( ...
                        maximumTileCostBytes, q.TileCostBytes);
                end
            end

            height = nan(imageSize);
            selected = find(rawValid);
            height(selected) = z(labelIndex(selected));
            projection = sweep.projectHeightMap( ...
                height, rawValid, DeltaHeight=options.DeltaHeight, ...
                Products=["Correspondence", "Observability"]);
            outputInfo = whos("height", "labelIndex", "best", ...
                "second", "previous", "next", "margin", ...
                "curvature", "validLabelCount", "confidence", ...
                "support", "costVolume");
            totalSeconds = toc(totalTimer);

            result = struct( ...
                "Channel", "Spin2T3", ...
                "ComputedChannels", "Spin2T3", ...
                "HeightLabelsMetres", z, ...
                "HeightMetres", projection.HeightMetres, ...
                "CorrespondenceXY", projection.CorrespondenceXY, ...
                "ObservabilityPixelsPerMetre", ...
                projection.ObservabilityPixelsPerMetre, ...
                "Valid", projection.Valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", validLabelCount, ...
                "ValidLabelFraction", validLabelCount ./ nl, ...
                "Spin2T3Confidence", confidence, ...
                "SupportFraction", support, ...
                "CostVolume", costVolume, ...
                "CostVolumeByChannel", ...
                GpuHeightSweep.optionalCostStruct( ...
                costVolume, options.StoreCostVolume, "Spin2T3"), ...
                "StoreCostVolumes", options.StoreCostVolume, ...
                "ExecutionTarget", target, ...
                "Preflight", plan, ...
                "Transport", "exact local A^T at every halo sample", ...
                "PixelConvention", ...
                "one-based [x,y]=[column,row] pixel centers", ...
                "WorldFrame", curve.Geometry.ReferenceCamera.WorldFrame, ...
                "ElevationDatum", ...
                curve.Geometry.ReferenceCamera.ElevationDatum, ...
                "Regularization", "none", ...
                "TileBoundaryPolicy", ...
                "core centers partitioned; exact integration halo", ...
                "SpatialHaloPixels", radius, ...
                "Runtime", struct( ...
                "TotalSeconds", totalSeconds, ...
                "SourceTransferSeconds", sourceTransferSeconds, ...
                "CpuGeometryAndJacobianSeconds", geometrySeconds, ...
                "ArrayKernelSeconds", arraySeconds, ...
                "ArrayReductionSeconds", reductionSeconds, ...
                "OutputTransferSeconds", outputTransferSeconds, ...
                "PixelCount", prod(imageSize), ...
                "LabelCount", nl, ...
                "PixelLabelCount", prod(imageSize) .* nl, ...
                "PixelLabelsPerSecond", ...
                prod(imageSize) .* nl ./ totalSeconds, ...
                "TileCount", tileCount, ...
                "TileSize", options.TileSize, ...
                "LabelBlockSize", options.LabelBlockSize, ...
                "MaximumTileCostBytes", maximumTileCostBytes, ...
                "OutputArrayBytes", sum([outputInfo.bytes]), ...
                "Execution", ...
                "single host coordinator; serial tiles; array kernels", ...
                "NumThreadWorkers", 0, ...
                "Precision", options.WorkingPrecision, ...
                "GeometryPrecision", "double"));
        end
    end

    methods (Static, Access = private)
        function q = evaluateZnccTile( ...
                curve, ref, refValid, mov, movValid, bounds, z, ...
                target, device, options)
            [cost, geometrySeconds, arraySeconds] = ...
                GpuHeightSweep.computeZnccTileCost( ...
                curve, ref, refValid, mov, movValid, bounds, z, ...
                target, device, options);

            reductionTimer = tic;
            s = GpuHeightSweep.summarizeCost(cost, z);
            GpuHeightSweep.synchronize(target, device);
            reductionSeconds = toc(reductionTimer);

            transferTimer = tic;
            names = fieldnames(s);
            for k = 1:numel(names)
                s.(names{k}) = GpuHeightSweep.toHost(s.(names{k}));
            end
            if options.StoreCostVolume
                hostCost = GpuHeightSweep.toHost(cost);
            else
                cs = [bounds(2) - bounds(1) + 1, ...
                    bounds(4) - bounds(3) + 1];
                hostCost = zeros([cs, 0], options.WorkingPrecision);
            end
            outputTransferSeconds = toc(transferTimer);
            q = s;
            q.CostVolume = hostCost;
            q.GeometrySeconds = geometrySeconds;
            q.ArraySeconds = arraySeconds;
            q.ReductionSeconds = reductionSeconds;
            q.OutputTransferSeconds = outputTransferSeconds;
            q.TileCostBytes = GpuHeightSweep.arrayBytes(cost);
        end

        function [cost, geometrySeconds, arraySeconds] = ...
                computeZnccTileCost( ...
                curve, ref, refValid, mov, movValid, bounds, z, ...
                target, device, options)
            %COMPUTEZNCC TILECOST Exact geometry with no host result gather.
            % Traceability: Algorithm 1 lines 4--9; G1.1 and G1.3.
            radius = curve.Reference.IntegrationRadius;
            rows = (bounds(1) - radius):(bounds(2) + radius);
            columns = (bounds(3) - radius):(bounds(4) + radius);
            [yy, xx] = ndgrid(rows, columns);
            p = [xx(:), yy(:)];
            es = [numel(rows), numel(columns)];
            cs = [bounds(2) - bounds(1) + 1, ...
                bounds(4) - bounds(3) + 1];
            ne = prod(es);
            nl = numel(z);

            arrayTimer = tic;
            [r, rv] = HeightSweepArrayKernels.bilinear( ...
                ref, p, ValidMask=refValid);
            r = reshape(r, es);
            rv = reshape(rv, es);
            GpuHeightSweep.synchronize(target, device);
            arraySeconds = toc(arrayTimer);
            cost = nan([cs, nl], "like", r);
            geometrySeconds = 0;
            for labelStart = 1:options.LabelBlockSize:nl
                labelEnd = min( ...
                    labelStart + options.LabelBlockSize - 1, nl);
                ids = labelStart:labelEnd;
                nb = numel(ids);
                pb = repmat(p, nb, 1);
                zb = repelem(reshape(z(ids), [], 1), ne);
                geometryTimer = tic;
                [w, warpValid] = curve.Geometry.warp(pb, zb);
                geometrySeconds = geometrySeconds + toc(geometryTimer);

                arrayTimer = tic;
                [m, mv] = HeightSweepArrayKernels.bilinear( ...
                    mov, w, ValidMask=movValid);
                m = reshape(m, [es, nb]);
                warpValid = GpuHeightSweep.toTarget( ...
                    reshape(warpValid, [es, nb]), target);
                joint = warpValid & reshape(mv, [es, nb]) & rv;
                c = HeightSweepArrayKernels.maskedZncc( ...
                    r, m, joint, curve.Reference.IntegrationKernel, ...
                    MinimumSupportFraction= ...
                    options.MinimumSupportFraction, ...
                    Epsilon=curve.Reference.Epsilon);
                cost(:, :, ids) = c;
                GpuHeightSweep.synchronize(target, device);
                arraySeconds = arraySeconds + toc(arrayTimer);
            end
        end

        function q = evaluateT3Tile( ...
                curve, rgx, rgy, refValid, mgx, mgy, movValid, ...
                bounds, z, target, device, options)
            radius = curve.Reference.IntegrationRadius;
            rows = (bounds(1) - radius):(bounds(2) + radius);
            columns = (bounds(3) - radius):(bounds(4) + radius);
            [yy, xx] = ndgrid(rows, columns);
            p = [xx(:), yy(:)];
            es = [numel(rows), numel(columns)];
            cs = [bounds(2) - bounds(1) + 1, ...
                bounds(4) - bounds(3) + 1];
            ne = prod(es);
            nl = numel(z);

            arrayTimer = tic;
            [rx, rvx] = HeightSweepArrayKernels.bilinear( ...
                rgx, p, ValidMask=refValid);
            [ry, rvy] = HeightSweepArrayKernels.bilinear( ...
                rgy, p, ValidMask=refValid);
            r = complex(rx, ry);
            rv = rvx & rvy & abs(r) >= options.MinimumGradient;
            r = reshape(r, es);
            rv = reshape(rv, es);
            GpuHeightSweep.synchronize(target, device);
            arraySeconds = toc(arrayTimer);
            cost = nan([cs, nl], "like", rx);
            bestRunning = inf(cs, "like", rx);
            confidenceBest = nan(cs, "like", rx);
            supportBest = nan(cs, "like", rx);
            geometrySeconds = 0;
            for labelStart = 1:options.LabelBlockSize:nl
                labelEnd = min( ...
                    labelStart + options.LabelBlockSize - 1, nl);
                ids = labelStart:labelEnd;
                nb = numel(ids);
                pb = repmat(p, nb, 1);
                zb = repelem(reshape(z(ids), [], 1), ne);
                geometryTimer = tic;
                [w, warpValid] = curve.Geometry.warp(pb, zb);
                [a, jacobianValid] = curve.Geometry.warpJacobian( ...
                    pb, zb, DeltaPixel=options.DeltaPixel);
                detA = a(:, 1, 1) .* a(:, 2, 2) ...
                    - a(:, 1, 2) .* a(:, 2, 1);
                orientationValid = ...
                    ~options.RequireOrientationPreserving | detA > 0;
                hostValid = warpValid & jacobianValid & orientationValid;
                geometrySeconds = geometrySeconds + toc(geometryTimer);

                arrayTimer = tic;
                [gx, vx] = HeightSweepArrayKernels.bilinear( ...
                    mgx, w, ValidMask=movValid);
                [gy, vy] = HeightSweepArrayKernels.bilinear( ...
                    mgy, w, ValidMask=movValid);
                at = GpuHeightSweep.toTarget(a, target);
                h = HeightSweepArrayKernels.transportGradient(gx, gy, at);
                valid = GpuHeightSweep.toTarget(hostValid, target) ...
                    & vx & vy & abs(h) >= options.MinimumGradient;
                h = reshape(h, [es, nb]);
                valid = reshape(valid, [es, nb]);
                [c, cf, ~, sp] = HeightSweepArrayKernels.spin2T3( ...
                    r, rv, h, valid, curve.Reference.IntegrationKernel, ...
                    MinimumSupportFraction= ...
                    options.MinimumSupportFraction, ...
                    Epsilon=curve.Reference.Epsilon);
                cost(:, :, ids) = c;
                for k = 1:nb
                    ck = c(:, :, k);
                    cfk = cf(:, :, k);
                    spk = sp(:, :, k);
                    better = isfinite(ck) & ck < bestRunning;
                    bestRunning(better) = ck(better);
                    confidenceBest(better) = cfk(better);
                    supportBest(better) = spk(better);
                end
                GpuHeightSweep.synchronize(target, device);
                arraySeconds = arraySeconds + toc(arrayTimer);
            end

            reductionTimer = tic;
            s = GpuHeightSweep.summarizeCost(cost, z);
            confidenceBest(~s.Valid) = NaN;
            supportBest(~s.Valid) = NaN;
            GpuHeightSweep.synchronize(target, device);
            reductionSeconds = toc(reductionTimer);

            transferTimer = tic;
            names = fieldnames(s);
            for k = 1:numel(names)
                s.(names{k}) = GpuHeightSweep.toHost(s.(names{k}));
            end
            confidenceBest = GpuHeightSweep.toHost(confidenceBest);
            supportBest = GpuHeightSweep.toHost(supportBest);
            if options.StoreCostVolume
                hostCost = GpuHeightSweep.toHost(cost);
            else
                hostCost = zeros([cs, 0], options.WorkingPrecision);
            end
            outputTransferSeconds = toc(transferTimer);
            if options.WorkingPrecision == "single"
                costBytes = 4 .* numel(cost);
            else
                costBytes = 8 .* numel(cost);
            end
            q = s;
            q.BestConfidence = confidenceBest;
            q.BestSupport = supportBest;
            q.CostVolume = hostCost;
            q.GeometrySeconds = geometrySeconds;
            q.ArraySeconds = arraySeconds;
            q.ReductionSeconds = reductionSeconds;
            q.OutputTransferSeconds = outputTransferSeconds;
            q.TileCostBytes = costBytes;
        end

        function s = summarizeCost(cost, z)
            nl = numel(z);
            finiteCost = isfinite(cost);
            count = sum(finiteCost, 3);
            sortable = cost;
            sortable(~finiteCost) = Inf;
            [sorted, order] = sort(sortable, 3, "ascend");
            best = sorted(:, :, 1);
            second = sorted(:, :, 2);
            labelIndex = order(:, :, 1);
            valid = count > 0 & isfinite(best);
            best(~valid) = NaN;
            second(count < 2 | ~isfinite(second)) = NaN;
            labelIndex(~valid) = 0;
            margin = second - best;

            cs = size(best);
            nt = prod(cs);
            base = reshape(cast(1:nt, "like", labelIndex), cs);
            safe = max(labelIndex, 1);
            previousIndex = base + (max(safe - 1, 1) - 1) .* nt;
            nextIndex = base + (min(safe + 1, nl) - 1) .* nt;
            previous = cost(previousIndex);
            next = cost(nextIndex);
            hasPrevious = valid & labelIndex > 1;
            hasNext = valid & labelIndex < nl;
            previous(~hasPrevious) = NaN;
            next(~hasNext) = NaN;
            interior = valid & labelIndex > 1 & labelIndex < nl;

            zt = cast(z, "like", best);
            safeVector = safe(:);
            hm = reshape(zt(safeVector) ...
                - zt(max(safeVector - 1, 1)), cs);
            hp = reshape(zt(min(safeVector + 1, nl)) ...
                - zt(safeVector), cs);
            curvature = cast(2, "like", best) .* ( ...
                previous ./ (hm .* (hm + hp)) ...
                - best ./ (hm .* hp) ...
                + next ./ (hp .* (hm + hp)));
            curvature(~interior | ~isfinite(previous) ...
                | ~isfinite(next)) = NaN;

            s = struct( ...
                "Valid", valid, ...
                "LabelIndex", labelIndex, ...
                "BestCost", best, ...
                "SecondBestCost", second, ...
                "CostMargin", margin, ...
                "PreviousLabelCost", previous, ...
                "NextLabelCost", next, ...
                "LocalCurvaturePerMetreSquared", curvature, ...
                "ValidLabelCount", count);
        end

        function a = toTarget(a, target)
            if target == "gpu"
                a = gpuArray(a);
            end
        end

        function a = toHost(a)
            if isa(a, "gpuArray")
                a = gather(a);
            end
        end

        function bytes = arrayBytes(a)
            if isa(a, "gpuArray")
                precision = string(classUnderlying(a));
            else
                precision = string(class(a));
            end
            if precision == "single"
                b = 4;
            elseif precision == "double"
                b = 8;
            elseif precision == "logical" || precision == "uint8"
                b = 1;
            else
                error("GpuHeightSweep:UnsupportedArrayClass", ...
                    "Cannot account for array class %s.", precision);
            end
            bytes = numel(a) .* b;
        end

        function synchronize(target, device)
            if target == "gpu"
                wait(device);
            end
        end

        function s = optionalCostStruct(cost, requested, name)
            if nargin < 3
                name = "Zncc";
            end
            if requested
                s = struct(name, cost);
            else
                s = struct;
            end
        end
    end
end

function mustBeGpuLabels(z)
if numel(z) < 3 || any(diff(z) <= 0)
    error("GpuHeightSweep:InvalidHeightLabels", ...
        "Height labels must contain at least three strictly increasing values.");
end
end
